import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';

const CATEGORIES = ['Travel', 'Meals', 'Accommodation', 'Office Supplies', 'Training', 'Other'];

export default function SubmitExpense() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    amount: '', currency: 'USD', category: '', description: '', date: '',
    vendor: '', expenseLines: [],
  });
  const [receipt, setReceipt] = useState(null);
  const [receiptPath, setReceiptPath] = useState(null); // path returned after OCR scan
  const [scanning, setScanning] = useState(false);
  const [scanned, setScanned] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Step 1: Upload receipt → OCR → auto-fill form
  const handleScan = async () => {
    if (!receipt) return;
    setScanning(true);
    setError('');
    try {
      const data = new FormData();
      data.append('receipt', receipt);
      const res = await api.post('/ocr/scan', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      const ocr = res.data;
      setForm((prev) => ({
        ...prev,
        amount: ocr.amount ?? prev.amount,
        currency: ocr.currency ?? prev.currency,
        date: ocr.date ?? prev.date,
        category: ocr.expenseType ?? prev.category,
        description: ocr.description ?? prev.description,
        vendor: ocr.vendor ?? prev.vendor,
        expenseLines: ocr.expenseLines ?? [],
      }));
      setReceiptPath(ocr.receiptPath);
      setScanned(true);
    } catch (err) {
      setError('OCR scan failed. Fill the form manually.');
    } finally {
      setScanning(false);
    }
  };

  // Step 2: Submit the (possibly edited) form
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = new FormData();
      const { expenseLines, vendor, ...rest } = form;
      Object.entries(rest).forEach(([k, v]) => data.append(k, v));
      // Pass OCR metadata as JSON
      data.append('ocrData', JSON.stringify({ vendor, expenseLines }));
      // If already scanned, send path; otherwise attach file
      if (receiptPath) data.append('receiptPath', receiptPath);
      else if (receipt) data.append('receipt', receipt);
      await api.post('/expenses', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      navigate('/employee');
    } catch (err) {
      setError(err.response?.data?.message || 'Submission failed');
    } finally {
      setLoading(false);
    }
  };

  const set = (key) => (e) => setForm({ ...form, [key]: e.target.value });

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2>Submit Expense</h2>
        {error && <p style={styles.error}>{error}</p>}

        {/* Receipt Upload + Scan */}
        <div style={styles.scanBox}>
          <label style={{ fontWeight: 600, display: 'block', marginBottom: '0.4rem' }}>
            📷 Scan Receipt (auto-fill)
          </label>
          <input type="file" accept=".jpg,.jpeg,.png,.pdf"
            onChange={(e) => { setReceipt(e.target.files[0]); setScanned(false); }} />
          <button type="button" style={styles.btnScan} onClick={handleScan}
            disabled={!receipt || scanning}>
            {scanning ? 'Scanning...' : 'Scan & Auto-fill'}
          </button>
          {scanned && <span style={styles.badge}>✓ Auto-filled from receipt</span>}
        </div>

        <form onSubmit={handleSubmit}>
          {/* Vendor */}
          <label style={styles.label}>Vendor / Merchant</label>
          <input style={styles.input} type="text" placeholder="e.g. McDonald's, Uber"
            value={form.vendor} onChange={set('vendor')} />

          {/* Amount + Currency */}
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <div style={{ flex: 2 }}>
              <label style={styles.label}>Amount *</label>
              <input style={styles.input} type="number" placeholder="0.00" required
                value={form.amount} onChange={set('amount')} />
            </div>
            <div style={{ flex: 1 }}>
              <label style={styles.label}>Currency *</label>
              <input style={styles.input} type="text" placeholder="USD"
                value={form.currency} onChange={(e) => setForm({ ...form, currency: e.target.value.toUpperCase() })} />
            </div>
          </div>

          {/* Category */}
          <label style={styles.label}>Expense Type *</label>
          <select style={styles.input} required value={form.category} onChange={set('category')}>
            <option value="">Select Category</option>
            {CATEGORIES.map((c) => <option key={c}>{c}</option>)}
          </select>

          {/* Date */}
          <label style={styles.label}>Date *</label>
          <input style={styles.input} type="date" required value={form.date} onChange={set('date')} />

          {/* Description */}
          <label style={styles.label}>Description</label>
          <textarea style={{ ...styles.input, height: '70px' }} placeholder="What was this expense for?"
            value={form.description} onChange={set('description')} />

          {/* Expense Lines (from OCR) */}
          {form.expenseLines.length > 0 && (
            <div style={styles.linesBox}>
              <strong>Expense Lines</strong>
              <table style={{ width: '100%', marginTop: '0.5rem', fontSize: '0.85rem' }}>
                <thead>
                  <tr>
                    <th style={{ textAlign: 'left' }}>Item</th>
                    <th style={{ textAlign: 'right' }}>Amount</th>
                  </tr>
                </thead>
                <tbody>
                  {form.expenseLines.map((line, i) => (
                    <tr key={i}>
                      <td>{line.description}</td>
                      <td style={{ textAlign: 'right' }}>{line.amount?.toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          <button style={styles.btn} type="submit" disabled={loading}>
            {loading ? 'Submitting...' : 'Submit Expense'}
          </button>
          <button type="button" style={{ ...styles.btn, background: '#6b7280', marginTop: '0.5rem' }}
            onClick={() => navigate('/employee')}>Cancel</button>
        </form>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: '#f0f2f5', padding: '2rem 0' },
  card: { background: '#fff', padding: '2rem', borderRadius: '8px', width: '440px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' },
  scanBox: { background: '#f0f9ff', border: '1px dashed #60a5fa', borderRadius: '6px', padding: '1rem', marginBottom: '1.5rem' },
  btnScan: { display: 'block', marginTop: '0.6rem', padding: '0.5rem 1rem', background: '#0ea5e9', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  badge: { display: 'inline-block', marginTop: '0.5rem', background: '#d1fae5', color: '#065f46', padding: '0.2rem 0.6rem', borderRadius: '999px', fontSize: '0.8rem' },
  label: { display: 'block', fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.2rem', color: '#374151' },
  input: { display: 'block', width: '100%', padding: '0.6rem', marginBottom: '1rem', borderRadius: '4px', border: '1px solid #ccc', boxSizing: 'border-box' },
  btn: { display: 'block', width: '100%', padding: '0.7rem', background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  error: { color: 'red', marginBottom: '1rem' },
  linesBox: { background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: '4px', padding: '0.75rem', marginBottom: '1rem' },
};
